final class WalletManager: ObservableObject {
    @Published var address: String = ""
    @Published var status: String = "Ready"
    @Published var balance: String = "0.0"

    private let privateKeyKey = "wallet.privateKey"
    private let publicKeyKey = "wallet.publicKey"
    private let apiBaseURL = URL(string: "https://api.example.com")!

    init() {
        loadOrCreateWallet()
    }

    func loadOrCreateWallet() {
        do {
            if let privateData = try? KeychainManager.shared.load(for: privateKeyKey),
               let publicData = try? KeychainManager.shared.load(for: publicKeyKey) {
                let pair = WalletKeyPair(privateKey: privateData, publicKey: publicData)
                address = Self.address(from: pair.publicKey)
                status = "Wallet loaded"
            } else {
                try generateWallet()
            }
        } catch {
            status = "Wallet error: \(error.localizedDescription)"
        }
    }

    func generateWallet() throws {
        let privateKey = P256.Signing.PrivateKey()
        let publicKey = privateKey.publicKey
        let pair = WalletKeyPair(privateKey: privateKey.rawRepresentation, publicKey: publicKey.rawRepresentation)
        try KeychainManager.shared.save(data: pair.privateKey, for: privateKeyKey)
        try KeychainManager.shared.save(data: pair.publicKey, for: publicKeyKey)
        address = Self.address(from: pair.publicKey)
        status = "New wallet created"
    }

    func signTransaction(message: String) -> String? {
        do {
            let privateData = try KeychainManager.shared.load(for: privateKeyKey)
            let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateData)
            let signature = try privateKey.signature(for: Data(message.utf8))
            return signature.derRepresentation.base64EncodedString()
        } catch {
            status = "Signing failed"
            return nil
        }
    }

    func sendTransaction(to recipient: String, amount: String) {
        let tx = Transaction(from: address, to: recipient, amount: amount, nonce: UUID().uuidString, timestamp: Date())
        guard let payload = try? JSONEncoder().encode(tx),
              let signature = signTransaction(message: String(data: payload, encoding: .utf8) ?? "") else {
            status = "Could not sign transaction"
            return
        }

        let signedTx = SignedTransaction(transaction: tx, signature: signature)
        guard let body = try? JSONEncoder().encode(signedTx) else {
            status = "Encoding failed"
            return
        }

        var request = URLRequest(url: apiBaseURL.appendingPathComponent("/transactions"))
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.httpBody = body

        status = "Submitting transaction..."

        URLSession.shared.dataTask(with: request) { [weak self] data, response, error in
            DispatchQueue.main.async {
                if let error = error {
                    self?.status = "Network error: \(error.localizedDescription)"
                    return
                }
                guard let http = response as? HTTPURLResponse, (200...299).contains(http.statusCode) else {
                    self?.status = "Transaction rejected"
                    return
                }
                self?.status = "Transaction submitted"
                self?.refreshBalance()
            }
        }.resume()
    }

    func refreshBalance() {
        let url = apiBaseURL.appendingPathComponent("/balance/\(address)")
        URLSession.shared.dataTask(with: url) { [weak self] data, response, error in
            DispatchQueue.main.async {
                if let data = data,
                   let result = try? JSONDecoder().decode(BalanceResponse.self, from: data) {
                    self?.balance = result.balance
                } else if let error = error {
                    self?.status = "Balance error: \(error.localizedDescription)"
                }
            }
        }.resume()
    }

    private static func address(from publicKeyData: Data) -> String {
        let hash = SHA256.hash(data: publicKeyData)
        return hash.compactMap { String(format: "%02x", $0) }.joined()
    }
}

